   105â†’// NewCompactorMetrics initializes metrics for Compactor.
   106â†’func NewCompactorMetrics(r prometheus.Registerer) *CompactorMetrics {
   107â†’	m := &CompactorMetrics{}
   108â†’
   109â†’	m.Ran = prometheus.NewCounter(prometheus.CounterOpts{
   110â†’		Name: "prometheus_tsdb_compactions_total",
   111â†’		Help: "Total number of compactions that were executed for the partition.",
   112â†’	})
   113â†’	m.PopulatingBlocks = prometheus.NewGauge(prometheus.GaugeOpts{
   114â†’		Name: "prometheus_tsdb_compaction_populating_block",
   115â†’		Help: "Set to 1 when a block is currently being written to the disk.",
   116â†’	})
   117â†’	m.OverlappingBlocks = prometheus.NewCounter(prometheus.CounterOpts{
   118â†’		Name: "prometheus_tsdb_vertical_compactions_total",
   119â†’		Help: "Total number of compactions done on overlapping blocks.",
   120â†’	})
   121â†’	m.Duration = prometheus.NewHistogram(prometheus.HistogramOpts{
   122â†’		Name:                            "prometheus_tsdb_compaction_duration_seconds",
   123â†’		Help:                            "Duration of compaction runs",
   124â†’		Buckets:                         prometheus.ExponentialBuckets(1, 2, 14),
   125â†’		NativeHistogramBucketFactor:     1.1,
   126â†’		NativeHistogramMaxBucketNumber:  100,
   127â†’		NativeHistogramMinResetDuration: 1 * time.Hour,
   128â†’	})
   129â†’	m.ChunkSize = prometheus.NewHistogram(prometheus.HistogramOpts{
   130â†’		Name:    "prometheus_tsdb_compaction_chunk_size_bytes",
   131â†’		Help:    "Final size of chunks on their first compaction",
   132â†’		Buckets: prometheus.ExponentialBuckets(32, 1.5, 12),
   133â†’	})
   134â†’	m.ChunkSamples = prometheus.NewHistogram(prometheus.HistogramOpts{
   135â†’		Name:    "prometheus_tsdb_compaction_chunk_samples",
   136â†’		Help:    "Final number of samples on their first compaction",
   137â†’		Buckets: prometheus.ExponentialBuckets(4, 1.5, 12),
   138â†’	})
   139â†’	m.ChunkRange = prometheus.NewHistogram(prometheus.HistogramOpts{
   140â†’		Name:    "prometheus_tsdb_compaction_chunk_range_seconds",
   141â†’		Help:    "Final time range of chunks on their first compaction",
   142â†’		Buckets: prometheus.ExponentialBuckets(100, 4, 10),
   143â†’	})
   144â†’
   145â†’	if r != nil {
   146â†’		r.MustRegister(
   147â†’			m.Ran,
   148â†’			m.PopulatingBlocks,
   149â†’			m.OverlappingBlocks,
   150â†’			m.Duration,
   151â†’			m.ChunkRange,
   152â†’			m.ChunkSamples,
   153â†’			m.ChunkSize,
   154â†’		)
   155â†’	}
   156â†’	return m
   157â†’}
