   439â†’// CompactBlockMetas merges many block metas into one, combining its source blocks together
   440â†’// and adjusting compaction level. Min/Max time of result block meta covers all input blocks.
   441â†’func CompactBlockMetas(uid ulid.ULID, blocks ...*BlockMeta) *BlockMeta {
   442â†’	res := &BlockMeta{
   443â†’		ULID: uid,
   444â†’	}
   445â†’
   446â†’	sources := map[ulid.ULID]struct{}{}
   447â†’	mint := blocks[0].MinTime
   448â†’	maxt := blocks[0].MaxTime
   449â†’
   450â†’	for _, b := range blocks {
   451â†’		if b.MinTime < mint {
   452â†’			mint = b.MinTime
   453â†’		}
   454â†’		if b.MaxTime > maxt {
   455â†’			maxt = b.MaxTime
   456â†’		}
   457â†’		if b.Compaction.Level > res.Compaction.Level {
   458â†’			res.Compaction.Level = b.Compaction.Level
   459â†’		}
   460â†’		for _, s := range b.Compaction.Sources {
   461â†’			sources[s] = struct{}{}
   462â†’		}
   463â†’		res.Compaction.Parents = append(res.Compaction.Parents, BlockDesc{
   464â†’			ULID:    b.ULID,
   465â†’			MinTime: b.MinTime,
   466â†’			MaxTime: b.MaxTime,
   467â†’		})
   468â†’	}
   469â†’	res.Compaction.Level++
   470â†’
   471â†’	for s := range sources {
   472â†’		res.Compaction.Sources = append(res.Compaction.Sources, s)
   473â†’	}
   474â†’	slices.SortFunc(res.Compaction.Sources, func(a, b ulid.ULID) int {
   475â†’		return a.Compare(b)
   476â†’	})
   477â†’
   478â†’	res.MinTime = mint
   479â†’	res.MaxTime = maxt
   480â†’	return res
   481â†’}
